from flask import Flask, request, jsonify
from collections import defaultdict, Counter
from sklearn.neural_network import MLPClassifier
import numpy as np
import pickle

app = Flask(__name__)

image_labels = defaultdict(list)
model = MLPClassifier(hidden_layer_sizes=(50,), max_iter=1000)

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    image_labels[image_id].append(label)
    return jsonify({'message': 'Label submitted successfully'}), 200

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        most_common_label = Counter(labels).most_common(1)[0][0]
        aggregated_labels[image_id] = most_common_label
    return jsonify(aggregated_labels), 200

@app.route('/train_model', methods=['POST'])
def train_model():
    images = []
    labels = []
    for image_id, label in aggregate_labels().json.items():
        images.append(load_image_data(image_id)) 
        labels.append(label)
    X = np.array(images)
    y = np.array(labels)
    model.fit(X, y)
    return jsonify({'message': 'Model trained successfully'}), 200

def load_image_data(image_id):
    # Placeholder function for loading image data
    return np.random.rand(10)

@app.route('/save_model', methods=['POST'])
def save_model():
    with open('model.pkl', 'wb') as f:
        pickle.dump(model, f)
    return jsonify({'message': 'Model saved successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)